// Get data from webhook
  const webhookData = $('Webhook1').first().json.body;
  const query = webhookData.query.toLowerCase();
  const intent = webhookData.intent || 'unknown'; // ← USE GEMINI'S INTENT!
  const studentData = $input.first().json;

  // Helper: find latest semester with grades
  const semesters = studentData.grades?.semesters ?? {};
  const latestSemesterKey = Object.keys(semesters).sort((a, b) => Number(b) - Number(a))[0];
  const latestSemester = semesters[latestSemesterKey] ?? {};

  // Base response
  let relevantData = {
    rollNumber: studentData.rollNumber,
    name: studentData.name
  };

  // Intent handling (using Gemini's intent from frontend)
  switch (intent) {
    case 'cgpa':
    case 'grades':  // Support both names
      relevantData.cgpa = latestSemester.cgpa ?? null;
      relevantData.sgpa = latestSemester.sgpa ?? null;
      relevantData.grades = latestSemester.endGrades ?? [];
      break;

    case 'attendance':
      relevantData.attendance = studentData.attendance ?? [];
      break;

    case 'faculty':
      relevantData.faculty = studentData.faculty ?? {};
      break;

    case 'courses':
    case 'course':
    case 'course_details':
      relevantData.courses =
        studentData.currentSemesterCourses ??
        studentData.registeredCourses?.map(c => ({
          code: c.code,
          name: c.title
        })) ??
        studentData.attendance?.map(a => ({
          code: a.code,
          name: a.name
        })) ??
        [];
      break;

    case 'general_status':  // ← THE NEW ONE!
      relevantData.cgpa = latestSemester.cgpa ?? null;
      relevantData.sgpa = latestSemester.sgpa ?? null;
      relevantData.attendance = studentData.attendance ?? [];
      relevantData.courses =
        studentData.currentSemesterCourses ??
        studentData.attendance?.map(a => ({
          code: a.code,
          name: a.name
        })) ??
        [];
      break;

    default:  // unknown - give everything
      relevantData = {
        rollNumber: studentData.rollNumber,
        name: studentData.name,
        cgpa: latestSemester.cgpa ?? null,
        attendance: studentData.attendance ?? [],
        courses:
          studentData.currentSemesterCourses ??
          studentData.attendance?.map(a => ({
            code: a.code,
            name: a.name
          })) ??
          []
      };
  }

  // Pass intent to LLM
  relevantData._intent = intent;

  // REQUIRED: return array
  return [{ json: relevantData }];

const studentData = $json;
const webhook = $('Webhook1').item.json.body;

const query = webhook.query;
const lastContext = webhook.lastContext;
const intent = studentData._intent || 'unknown';

let contextHint = '';
let responseStyle = 'one short, clear sentence';

if (intent === 'general_status') {
  contextHint = `
IMPORTANT:
User wants an OVERALL SUMMARY.
Provide CGPA, average attendance, and number of courses.
Keep to 2–3 sentences max.
`;
  responseStyle = '2–3 short sentences';
}

const prevContext = lastContext
  ? `Previous question: ${lastContext.lastQuery}
Previous answer: ${lastContext.lastResponse}`
  : 'None';

const prompt = `
You are an academic assistant.

You will receive structured student data.
Answer the question using ONLY that data.

Student Data:
${JSON.stringify(studentData, null, 2)}

Question: ${query}

Previous Context:
${prevContext}

${contextHint}

Rules:
- If data exists, answer directly.
- If missing, say: "I don't have that information."
- Answer in ${responseStyle}.
- Do not explain your reasoning.
`;

return {
  prompt
};
